import { useState } from "react";

const toppings = [
  "🧀",
  "🍅",
  "🍄",
  "🫒",
  "🌽",
  "🧅",
  "🌶️",
  "🍍",
];

export default function PizzaBuilder() {
  const [pizza, setPizza] = useState([]);

  function addTopping(topping) {
    setPizza([...pizza, topping]);
  }

  function clearPizza() {
    setPizza([]);
  }

  return (
    <div className="container">
      <h1>🍕 Pizza Builder</h1>

      <h2>Pizza</h2>

      <div style={{ fontSize: "4rem", minHeight: "5rem" }}>
        🍕 {pizza.join(" ")}
      </div>

      <h2>Toppings</h2>

      <div>
        {toppings.map(topping => (
          <button
            key={topping}
            onClick={() => addTopping(topping)}
          >
            {topping}
          </button>
        ))}
      </div>

      <button onClick={clearPizza}>
        Clear
      </button>

      <p>{pizza.length} topping(s)</p>
    </div>
  );
}
